// Generated by Claude
use crate::library::helper::{RODIO_SUPPORTED_FORMATS, is_rodio_supported};

// ── is_rodio_supported ───────────────────────────────────────────────────────
// These tests use temp files so no test_assets dependency.

use std::{fs::File, path::PathBuf};
use tempfile::tempdir;

#[test]
fn supported_extensions_return_true() {
    let dir = tempdir().unwrap();
    for ext in &RODIO_SUPPORTED_FORMATS {
        let path = dir.path().join(format!("audio.{}", ext));
        File::create(&path).unwrap();
        assert_eq!(
            is_rodio_supported(&path).unwrap(),
            true,
            "Expected true for .{}",
            ext
        );
    }
}

#[test]
fn unsupported_extension_returns_false() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("audio.aiff");
    File::create(&path).unwrap();
    assert_eq!(is_rodio_supported(&path).unwrap(), false);
}

#[test]
fn no_extension_returns_err() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("audiofile");
    File::create(&path).unwrap();
    assert!(is_rodio_supported(&path).is_err());
}

#[test]
fn directory_path_returns_err() {
    let dir = tempdir().unwrap();
    assert!(is_rodio_supported(dir.path()).is_err());
}

#[test]
fn nonexistent_path_returns_err() {
    let path = PathBuf::from("/nonexistent/path/audio.flac");
    assert!(is_rodio_supported(&path).is_err());
}
